  <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Offline-Krypto-Zahlungsreibung vs. die INSPAY × Sui-Lösung</text>
  <g font-family="sans-serif">
    <rect x="24" y="55" width="315" height="300" rx="10" fill="#1c1c1f" stroke="#f87171" stroke-width="1.5"/>
