    <rect x="361" y="55" width="315" height="300" rx="10" fill="#1c1c1f" stroke="#22c55e" stroke-width="1.5"/>
    <text x="518" y="86" fill="#22c55e" font-size="14" font-weight="700" text-anchor="middle">INSPAY × Sui (USDsui)</text>
    <text x="518" y="126" fill="#e4e4e7" font-size="14" text-anchor="middle">Finalität: ~0,4 Sek (390-400ms)</text>
    <text x="518" y="158" fill="#e4e4e7" font-size="14" text-anchor="middle">Gas: 0 Yen (Sponsored Tx)</text>
    <text x="518" y="190" fill="#e4e4e7" font-size="13" text-anchor="middle">Hürde: kein SUI, nur USDsui</text>
    <text x="518" y="222" fill="#e4e4e7" font-size="13" text-anchor="middle">Debüt: 2026-07-13/14 WebX Tokio</text>
